package com.knoxhack.echostationfall.integration;
import com.knoxhack.echocore.api.*; import com.knoxhack.echostationfall.EchoStationfall; import com.knoxhack.echostationfall.progression.*; import com.knoxhack.echostationfall.world.*; import com.knoxhack.echoorbitalremnants.suit.SuitState; import java.util.*; import java.util.concurrent.atomic.AtomicBoolean; import net.minecraft.resources.Identifier; import net.minecraft.server.level.ServerLevel; import net.minecraft.world.entity.player.Player;
public final class StationfallCoreIntegration{private static final AtomicBoolean REGISTERED=new AtomicBoolean(false); private StationfallCoreIntegration(){} public static void register(){if(!REGISTERED.compareAndSet(false,true))return; EchoAddonRegistry.register(CHAPTER); EchoCoreServices.registerRouteRecordService(StationfallCoreIntegration::routes); EchoCoreServices.registerDiagnosticService(StationfallCoreIntegration::diagnostics); EchoCoreServices.registerHazardTelemetryService(StationfallCoreIntegration::telemetry);} private static final EchoAddonChapter CHAPTER=new EchoAddonChapter(){public String id(){return "stationfall";} public String modId(){return EchoStationfall.MODID;} public String displayName(){return "ECHO: Stationfall";} public String summary(){return "Board the dead orbital station, restore nine sections, stabilize major sections, survive Signal Panic, and recover the Stationfall Blackbox.";} public boolean isAvailable(Player p){return p!=null&&StationfallProgress.get(p).canBoard(p);} public String statusLine(Player p){StationfallProgress pr=StationfallProgress.get(p); if(!pr.canBoard(p))return "Locked behind Orbital Remnants station coordinates or Station Network restoration."; if(pr.blackboxRetrieved())return "Stationfall Blackbox recovered. Blackbox Protocol handoff exposed."; return pr.poweredSectionCount()+"/9 sections stable, "+pr.decodedLogCount()+"/9 crew logs decoded, "+pr.objectiveCount()+"/"+StationfallObjective.values().length+" objectives stabilized.";}}; private static List<EchoRouteRecord> routes(Player p){StationfallProgress pr=StationfallProgress.get(p); boolean c=pr.blackboxRetrieved(); return List.of(new EchoRouteRecord(id("stationfall_route"),"stationfall","Stationfall Boarding Route","Dungeon","echostationfall:stationfall_station",!pr.canBoard(p)?"LOCKED":c?"BLACKBOX RECOVERED":pr.boarded()?"ACTIVE":"READY",summary(p),c));} private static List<EchoDiagnosticBlocker> diagnostics(Player p){StationfallProgress pr=StationfallProgress.get(p); List<EchoDiagnosticBlocker> list=new ArrayList<>(); if(!pr.canBoard(p))list.add(new EchoDiagnosticBlocker(id("stationfall_orbital_gate"),"stationfall",EchoDiagnosticBlocker.Severity.BLOCKED,"Stationfall route locked","Orbital station coordinates or Station Network restoration are missing.","Complete Orbital Remnants station coordinates/network progress.")); SuitState suit=SuitState.get(p); if(StationfallDimensions.isStation(p.level())&&(suit.oxygen()<=25||suit.pressure()<=25))list.add(new EchoDiagnosticBlocker(id("stationfall_suit_critical"),"stationfall",EchoDiagnosticBlocker.Severity.CRITICAL,"Suit reserves critical","Oxygen "+suit.oxygen()+"%, pressure "+suit.pressure()+"%.","Use Emergency Oxygen Pack, Pressure Seal Kit, or restore local power.")); SignalPanicState panic=SignalPanicState.get(p); if(panic.critical())list.add(new EchoDiagnosticBlocker(id("stationfall_signal_panic"),"stationfall",EchoDiagnosticBlocker.Severity.WARNING,"Signal Panic critical","False ECHO events and door hallucinations are active.","Move to stable power or use a Signal Panic Dampener.")); return List.copyOf(list);} private static EchoHazardTelemetry telemetry(Player p){if(!StationfallDimensions.isStation(p.level()))return EchoHazardTelemetry.nominal(); SuitState suit=SuitState.get(p); SignalPanicState panic=SignalPanicState.get(p); StationSection sec=StationSection.fromPosition(p.blockPosition()); StationPowerState power=StationPowerState.EMERGENCY; if(p.level() instanceof ServerLevel sl)power=StationfallStationState.get(sl).powerState(sec); int exposure=Math.max(panic.value(),power.hostile()?55:15); return new EchoHazardTelemetry(100,0,0,suit.oxygen(),suit.pressure(),0,power==StationPowerState.OVERLOADED?45:0,exposure,"Stationfall: "+sec.displayName()+" / "+power.displayName()+" / Signal Panic "+panic.value()+"%");} private static String summary(Player p){StationfallProgress pr=StationfallProgress.get(p); if(!pr.canBoard(p))return "Dead station route is sealed until Orbital Remnants resolves station coordinates/network access."; if(StationfallDimensions.isStation(p.level())){StationSection s=StationSection.fromPosition(p.blockPosition());return "Current section: "+s.displayName()+". "+pr.poweredSectionCount()+"/9 stable, "+pr.decodedLogCount()+"/9 logs, "+pr.objectiveCount()+"/"+StationfallObjective.values().length+" objectives.";} return "Board from Low Earth Orbit with the Station Access Card or Terminal BOARD STATION action.";} private static Identifier id(String p){return Identifier.fromNamespaceAndPath(EchoStationfall.MODID,p);} }
